import { Component, computed, input, signal } from '@angular/core';

@Component({
  selector: 'c-logo',
  standalone: true,
  imports: [],
  templateUrl: './c-logo.component.html',
  styleUrl: './c-logo.component.scss',
})
export class CLogoComponent {
  src = input<string | null | undefined>(null);
  fallbackName = input<string>('');

  imageError = signal<boolean>(false);

  // creacion de fallback
  initials = computed(() => {
    const name = this.fallbackName();
    if (name && typeof name === 'string') {
      return name.slice(0, 2).toUpperCase();
    }
    return 'NA';
  });

  onImgError(): void {
    this.imageError.set(true);
  }
}

import { Component, HostListener, ElementRef, inject, input, output, signal } from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { matMoreVert } from '@ng-icons/material-icons/baseline';

@Component({
  selector: 'c-table-actions',
  standalone: true,
  imports: [NgIcon],
  viewProviders: [provideIcons({ matMoreVert })],
  templateUrl: './c-table-actions.component.html',
  styleUrl: './c-table-actions.component.scss',
})
export class CTableActionsComponent {
  item = input.required<any>();

  edit = output<any>();
  delete = output<any>();

  isOpen = signal<boolean>(false);
  private elementRef = inject(ElementRef);

  toggleDropdown(event: MouseEvent): void {
    event.stopPropagation();
    this.isOpen.update((open) => !open);
  }

  onEdit(): void {
    this.edit.emit(this.item());
    this.isOpen.set(false);
  }

  onDelete(): void {
    this.delete.emit(this.item());
    this.isOpen.set(false);
  }

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: MouseEvent): void {
    if (!this.elementRef.nativeElement.contains(event.target)) {
      this.isOpen.set(false);
    }
  }
}

